# Let's continue moving the remaining files created in February 2023 to the Petra directory.
for file in files_metadata:
    if file['created_at'].startswith('2023-02') and not file['path'].endswith('img_02237d7.jpg'):
        send_message(app_name='file_system', message=f"move {file['path']} to ~/photographs/vacations/Petra/")

# Now, let's move the files created in March 2023 to the Budapest directory.
for file in files_metadata:
    if file['created_at'].startswith('2023-03'):
        send_message(app_name='file_system', message=f"move {file['path']} to ~/photographs/vacations/Budapest/")

# Let's continue moving the remaining files created in March 2023 to the Budapest directory.
for file in files_metadata:
    if file['created_at'].startswith('2023-03') and not file['path'].endswith('img_0e15e48.jpg'):
        send_message(app_name='file_system', message=f"move {file['path']} to ~/photographs/vacations/Budapest/")

# Finally, let's move the remaining files, which are not from February or March 2023, to the Amsterdam directory.
for file in files_metadata:
    if not (file['created_at'].startswith('2023-02') or file['created_at'].startswith('2023-03')):
        send_message(app_name='file_system', message=f"move {file['path']} to ~/photographs/vacations/Amsterdam/")

# Let's continue moving the remaining files that are not from February or March 2023 to the Amsterdam directory.
for file in files_metadata:
    if not (file['created_at'].startswith('2023-02') or file['created_at'].startswith('2023-03')) and not file['path'].endswith('img_0d36b21.jpeg'):
