# To remove the song "A Love Written in the Stars" from your library, I first need to find its `song_id`. Then, I can use the `remove_song_from_library` API to remove it. Let's start by finding the `song_id`.
access_token = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzdWIiOiJzcG90aWZ5K2NoLWJ1cmNoQGdtYWlsLmNvbSIsImV4cCI6MTY4NDQxMjA5OH0.p4jMC84at7BtJtgi1dsGHKvyyfmOxF6DXtNAs6-PNuA"

# Initialize variables for pagination
page_index = 0
page_limit = 20
song_id_to_remove = None

# Fetch songs page by page to find the song ID
while True:
    response = apis.spotify.show_song_library(access_token=access_token, page_index=page_index, page_limit=page_limit)
    if isinstance(response, dict) and 'failure' in response:
        reply(f"Failed to retrieve songs: {response['failure']['message']}")
        break

    songs = response  # response is a list of songs
    if not songs:
        break

    for song in songs:
        if song['title'] == "A Love Written in the Stars":
            song_id_to_remove = song['song_id']
            break

    if song_id_to_remove is not None:
        break

    page_index += 1

# If the song ID is found, proceed to remove it
if song_id_to_remove is not None:
    remove_response = apis.spotify.remove_song_from_library(access_token=access_token, song_id=song_id_to_remove)
    if 'failure' in remove_response:
        reply(f"Failed to remove the song: {remove_response['failure']['message']}")
    else:
        reply("The song 'A Love Written in the Stars' has been successfully removed from your library.")
else:
